form:Form.form:Scripts:
		var RS;
var CFG,CHLCFG;
var TIT=null;

//Actualiza la Lista
function LoadList(force)
{
  var proxy=GetProxy(); //as NomadProxy
  var param=new NomadXML("DATA");
  var lst=Ctrl("LIST");

  var max=CFG.GetAttrInt("maxreg");
  if (isNaN(max)) max=0;

  if (force || Ctrl("VALUES").GetXValue()=="*" || Ctrl("VALUES").GetXValue()=="" )
  {
  param.SetAttr("parent" ,Ctrl("PARENT").GetXValue());
  param.SetAttr("order"  ,Ctrl("ORDER").GetXValue().substr(1));
  param.SetAttr("asc"    ,Ctrl("ORDER").GetXValue().substr(0,1)=="+"?"1":"0");


  //deptos
  if(Ctrl("DEPARTAMENTOS").CountRow()>0)
  { 
  	var dptos = "";
    for(i=0;i<Ctrl("DEPARTAMENTOS").CountRow();i++)
  	{
  		dptos += Ctrl("DEPARTAMENTOS").GetRow(i).GetAttr("id")+",";  		
  	}

  	dptos = dptos.substring(0, dptos.length - 1);
  	param.SetAttr("dptos" ,dptos);
  }


  if (Ctrl("BUSCAR")) param.SetAttr("search" ,Ctrl("BUSCAR").GetXValue());
  if (max>0) param.SetAttr("LEN",max);

  //Agrego los Parametros Adicionales
  for (cur=CFG.FirstChild(); cur!=null; cur=cur.Next())
  {
  	if (Ctrl(cur.GetAttr("name")))
  		param.SetAttr(cur.GetAttr("name"), Ctrl(cur.GetAttr("name")).GetXValue());

	//Faltan algunos Parametros  		
  	if (cur.GetAttrBool("req") && Ctrl(cur.GetAttr("name")).GetXValue()=="")
  	{
	  Ctrl("VALUES").SetXValue("");
	  Ctrl("LIST_REG").SetXValue("Especifique algún criterio de búsqueda.");

		//Limpio todo
	  lst.IDs=new Array();
	  lst.SetXValue("");          

		//Mensaje Inicial de la Lista
		lst.MsgEmply="Especifique algún criterio de búsqueda...";
		lst.ResetSQL();
  		return;
  	}
  }

  //Cargo el RS
  if(CFG.GetAttr("METHOD")!="")
  {
    var ca=proxy.RPCService();
    ca.AddParam(new NomadRPCParamOut("OUT", "Nomad.NSystem.Object", "Nomad.NSystem.Proxy.NomadXML"));

    //Lista de Parametros
    var p=0;
    var mecfg=new NomadXML(Ctrl("main").getResource("QRY_IDS_METHOD"));
    for (cur=mecfg.FirstChild(); cur!=null; cur=cur.Next())
    {
      switch(cur.GetAttr("value").split(":")[0])
      {
        case "ctrl":
          p++;
          ca.AddParam(new NomadRPCParam("P"+p, "IN", Ctrl(cur.GetAttr("value").substr(5)).GetXValue(), "String"));
          break;
        case "const":
          p++;
          ca.AddParam(new NomadRPCParam("P"+p, "IN", cur.GetAttr("value").substr(6), "String"));
          break;
        default:
          if (cur.GetAttr("value")!="")
          {
            p++;
            ca.AddParam(new NomadRPCParam("P"+p, "IN", cur.GetAttr("value"), "String"));
          }
          break;
      }
    }

    ca.Execute(CFG.GetAttr("METHOD").split(":")[0],CFG.GetAttr("METHOD").split(":")[1]);
    RS=new NomadXML(ca.GetParam("OUT").Data);
  } else
  {
    RS=proxy.SQLService().GetXML(Ctrl("main").getResource("QRY_IDS"), param.ToString());
  }

  //Actualizo el Label
  var total=RS.GetAttrInt("total"); if (isNaN(total)) total=0;
  var count=RS.GetAttrInt("count"); if (isNaN(count)) count=0;


//Limpio la Lista
  lst.IDs=new Array();

  //Genero la Lista de IDS                                
  var found=false;
  for (var cur=RS.FirstChild(); cur!=null; cur=cur.Next())
  	if (max==0 || lst.IDs.length<max)
  	{
    	lst.IDs.push(cur.GetAttr("id"));
    	if (cur.GetAttr("id")==lst.GetXValue()) found=true;
    }

  Ctrl("VALUES").SetXValue(lst.IDs.length>100 ? "*" : lst.IDs.join("|"))
  } else
  {
//Cargo la Lista
  lst.IDs=Ctrl("VALUES").GetXValue().split("|");
  count=lst.IDs.length
  }

  if (max>0 && count>=max)
  {                      
  	if (count==max)
  		Ctrl("LIST_REG").SetXValue("Primeros "+max+" registros");
  	else                                                      
  		Ctrl("LIST_REG").SetXValue("ERROR AL MOSTRAR LA CANTIDAD DE REGISTROS ("+max+"!="+count+")");
  } else            
  if (count==0)
  {
  	Ctrl("LIST_REG").SetXValue("No hay registros");
  } else
  {
  	Ctrl("LIST_REG").SetXValue(count + " registros");
  }


  lst.MsgEmply="No hay registros";
  if (!found) lst.SetXValue("");
  lst.ResetSQL();
}

//Habilita los Botones
function EnabledButtons()
{
  var cur,f;
  if (Ctrl("LIST").GetXValue()=="" || Ctrl("LIST").TotalRow<=0)
  {
    CtrlEnabled("SHOW"  ,false);
    CtrlEnabled("ACCEPT",false);
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,false);
    CtrlEnabled("DELETE",false);
    CtrlEnabled("ADMIN" ,false);

    //Buscar que botones estan habilitados siempre
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
    {
      f=cur.GetAttrInt("flag");
      CtrlEnabled(cur.GetAttr("name"), (f==2?CheckEnabledButton(cur.GetAttr("name")):false));
    }
  } else
  if (Ctrl("LIST").GetSelectAttrValue("lock")!="")
  {
    CtrlEnabled("SHOW"  ,CheckEnabledButton("SHOW"));
    CtrlEnabled("ACCEPT",CheckEnabledButton("ACCEPT"));
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,Ctrl("LIST").GetSelectAttrValue("lock")=="2"?CheckEnabledButton("EDIT"):false);
    CtrlEnabled("DELETE",false);
    CtrlEnabled("ADMIN" ,(GetProxy().Admin()?CheckEnabledButton("ADMIN"):false));

    //Buscar que botones estan habilitados si esta bloqueado
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
    {
      f=cur.GetAttrInt("flag");
      CtrlEnabled(cur.GetAttr("name"), (f==2?CheckEnabledButton(cur.GetAttr("name")):false));
    }
  } else
  {
    CtrlEnabled("SHOW"  ,CheckEnabledButton("SHOW"));
    CtrlEnabled("ACCEPT",CheckEnabledButton("ACCEPT"));
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,CheckEnabledButton("EDIT"));
    CtrlEnabled("DELETE",CheckEnabledButton("DELETE"));
    CtrlEnabled("ADMIN" ,(GetProxy().Admin()?CheckEnabledButton("ADMIN"):false));

    //Habilitar todos los botones
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
      CtrlEnabled(cur.GetAttr("name"), CheckEnabledButton(cur.GetAttr("name")));
  }
}

function InternalRefresh(force)
{
  LoadList(force);
  EnabledButtons();
}

function RefreshList(force)
{                  
if (CFG.GetAttr("autoload")!="0" || force || Ctrl("VALUES").GetXValue()!="")
{                     
var lst=Ctrl("LIST");

//Limpio la Lista
lst.IDs=new Array();

//Mensaje Inicial de la Lista
lst.MsgEmply="Cargando...";
lst.ResetSQL();

NomadTimeout("InternalRefresh("+(CFG.GetAttr("autoload")!="0" || force?"true":"false")+");", 200, "Cargando la lista...");
} else                               
EnabledButtons();
}

function ReplaceResource(recID)
{
  var recValue=Ctrl("main").getResource(recID);
  recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
  recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
  recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
  recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

  Ctrl("main").setResource(recValue, recID);
}

///////////////////////////////////////////////////////////////////////////////
//EVENTOS
function OnLoad()
{
  //Cargo la Configuracion
  CFG   =new NomadXML(Ctrl("main").getResource("QRY_CFG"));
  CHLCFG=new NomadXML(Ctrl("main").getResource("QRY_CHILD"));

  //Mensaje Inicial de la Lista
  Ctrl("LIST").MsgEmply=(CFG.GetAttr("autoload")!="0"?"Cargando...":"Especifique algún criterio de búsqueda...");
  Ctrl("LIST_REG").SetXValue(CFG.GetAttr("autoload")!="0"?"Cargando...":"Especifique algún criterio de búsqueda.");

  //Modifico los Recursos
  ReplaceResource("QRY_IDS");
  ReplaceResource("QRY_IDS_LIST");
  ReplaceResource("QRY_IDS_METHOD");
  ReplaceResource("QRY_IDS_PARENT");

  //Actualizo el Titulo
  if ((CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
  {
    if (TIT==null)
      TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

  while(TIT!=null)
  {
    if (TIT.GetAttr("descr")!="")
      Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
    TIT=TIT.FirstChild();
  }
  }

  //Cargo la Lista
  RefreshList(false);

  //Evento PosONLOAD
  PosOnLoad();       



}

function PosOnLoad()
{
}

function CheckEnabledButton(name)
{
	return true;
}

function OnReady()
{
  //Cargo la Configuracion
  if (Ctrl("BUSCAR")) Ctrl("BUSCAR").SetFocus();
}

function OnActivate()
{
  //Cargo la Lista
  RefreshList(false);
}                   

function OnSearch()
{
  //Cargo la Lista
  RefreshList(true);
}                   

function OnRefresh()
{
  //Cargo la Lista
  RefreshList(true);
}                   

function OnOrder()
{
  Ctrl("ORDER").SetXValue((Ctrl("LIST").OrderMode=="ASC"?"+":"-")+Ctrl("LIST").OrderBy);
  RefreshList(true);
}

///////////////////////////////////////////////////////////////////////////////
//ACCIONES
function RegShow()
{
  if (Ctrl("SHOW")?false:true) return false;
  if (!Ctrl("SHOW").GetEnabled()) return false;

  Ctrl("main").DoEvent("SHOW"  );
  return true;
}
function RegAdd()
{
  if (Ctrl("ADD")?false:true) return false;
  if (!Ctrl("ADD").GetEnabled()) return false;

  Ctrl("main").DoEvent("ADD"   );
  return true;
}
function RegEdit()
{
  if (Ctrl("EDIT")?false:true) return false;
  if (!Ctrl("EDIT").GetEnabled()) return false;

  Ctrl("main").DoEvent("EDIT"  );
  return true;
}
function RegDelete()
{
  if (Ctrl("DELETE")?false:true) return false;
  if (!Ctrl("DELETE").GetEnabled()) return false;
  if (!confirm("¿Esta seguro que quiere eliminar el Registro?")) return false;

  Ctrl("main").DoEvent("DELETE");
  return true;
}
function RegAdmin()
{
  if (Ctrl("ADMIN")?false:true) return false;
  if (!Ctrl("ADMIN").GetEnabled()) return false;

  Ctrl("main").DoEvent("ADMIN" );
  return true;
}

function ActionBACK()
{
  if (Ctrl("BACK")?false:true) return false;
  if (!Ctrl("BACK").GetEnabled()) return false;
  if (!confirm("¿Esta seguro que quiere Salir de la Pantalla?")) return false;

  Ctrl("main").DoEvent("BACK"  );
  return true;
}
function ActionNEXT()
{
  if (Ctrl("NEXT")?false:true) return false;
  if (!Ctrl("NEXT").GetEnabled()) return false;

  Ctrl("main").DoEvent("NEXT"  );
  return true;
}
function ActionPREV()
{
  if (Ctrl("PREV")?false:true) return false;
  if (!Ctrl("PREV").GetEnabled()) return false;

  Ctrl("main").DoEvent("PREV"  );
  return true;
}
function ActionEND()
{
  if (Ctrl("END")?false:true) return false;
  if (!Ctrl("END").GetEnabled()) return false;
  if (!confirm("¿Esta seguro que quiere Terminar la Operacion?")) return false;

  Ctrl("main").DoEvent("BACK"  );
  return true;
}
function DependCall(obj)
{
  var flowId=CHLCFG.FindElement2("CHILD","name",obj.ID()).GetAttr("flow");
  var flag  =CHLCFG.FindElement2("CHILD","name",obj.ID()).GetAttr("flag");

  if (Ctrl("LIST").GetXValue()=="") if(flag!="2") return;

  if (flowId.indexOf(":")>=0)
    appendFormInMain(flowId.split(":")[0], flowId.split(":")[1], '<DATA PARENT="'+Ctrl("LIST").GetXValue()+'" GRAND="'+Ctrl("PARENT").GetXValue()+'" />');
  else
    appendFormInMain(flowId              , "LIST"              , '<DATA PARENT="'+Ctrl("LIST").GetXValue()+'" GRAND="'+Ctrl("PARENT").GetXValue()+'" />');
}
